import { Context, Next } from 'hono';
import { v4 as uuidv4 } from 'uuid';
import nodemailer from 'nodemailer';

// Mock database to store notifications
const notificationDB: Notification[] = [];

interface Notification {
  id: string;
  userIds: string[];
  message: string;
  status: 'pending' | 'sent' | 'failed';
}

// Email configuration for nodemailer
const transporter = nodemailer.createTransport({
  service: 'gmail',
  auth: {
    user: 'your-email@gmail.com',
    pass: 'your-password'
  }
});

export const notificationRoute = async (c: Context, next: Next) => {
  // Check if the caller is a system service account
  const caller = c.req.headers.get('X-Caller');
  if (caller !== 'system-service-account') {
    return c.json({ error: 'Unauthorized' }, 401);
  }

  // Parse request body
  const { userIds, message } = await c.req.json();

  if (!userIds || !message) {
    return c.json({ error: 'Missing required fields' }, 400);
  }

  // Create a new notification
  const notificationId = uuidv4();
  const newNotification: Notification = {
    id: notificationId,
    userIds,
    message,
    status: 'pending'
  };

  // Persist the notification in the database
  notificationDB.push(newNotification);

  // Dispatch notifications via email and push (mock implementation)
  for (const userId of userIds) {
    try {
      await sendEmail(userId, newNotification.message);
      await sendPushNotification(userId, newNotification.message);
      newNotification.status = 'sent';
    } catch (error) {
      newNotification.status = 'failed';
    }
  }

  // Update the notification in the database
  const index = notificationDB.findIndex(n => n.id === notificationId);
  if (index !== -1) {
    notificationDB[index] = newNotification;
  }

  return c.json(newNotification, 201);
};

const sendEmail = async (userId: string, message: string) => {
  // Mock email sending logic
  console.log(`Sending email to user ${userId}: ${message}`);
};

const sendPushNotification = async (userId: string, message: string) => {
  // Mock push notification sending logic
  console.log(`Sending push notification to user ${userId}: ${message}`);
};

import { Hono } from 'hono';
import { notificationRoute } from './routes/notifications';

const app = new Hono();

app.post('/notifications', notificationRoute);

export default app;

